#include <iostream>
#include <unordered_map>
#include <string>

struct UserProfile {
    std::string name;
    int age;
    std::string email;
};

class UserHashTable {
private:
    std::unordered_map<std::string, UserProfile> users;

public:
    void addUser(const std::string& userId, const UserProfile& profile) {
        users[userId] = profile;
    }

    UserProfile* findUser(const std::string& userId) {
        auto it = users.find(userId);
        if (it != users.end()) {
            return &it->second;
        }
        return nullptr;
    }
};

int main() {
    UserHashTable userTable;

    // Adding some users
    UserProfile profile1 = {"Alice", 30, "alice@example.com"};
    UserProfile profile2 = {"Bob", 25, "bob@example.com"};
    userTable.addUser("user1", profile1);
    userTable.addUser("user2", profile2);

    // Searching for a user
    std::string searchId = "user1";
    UserProfile* foundUser = userTable.findUser(searchId);

    if (foundUser) {
        std::cout << "Name: " << foundUser->name << ", Age: " << foundUser->age << ", Email: " << foundUser->email << std::endl;
    } else {
        std::cout << "User not found." << std::endl;
    }

    return 0;
}